// Newsjacking sources: Google News RSS + HN front-page + key blogs
return [
  { json: { source: 'google_news', topic: 'manifest v3 ad blocker', url: 'https://news.google.com/rss/search?q=%22manifest+v3%22+ad+blocker&hl=en&gl=US' }},
  { json: { source: 'google_news', topic: 'youtube anti adblock', url: 'https://news.google.com/rss/search?q=%22youtube%22+%22ad+blocker%22+(crackdown+OR+block+OR+ban)&hl=en' }},
  { json: { source: 'google_news', topic: 'chrome extension policy', url: 'https://news.google.com/rss/search?q=chrome+extension+policy+OR+%22chrome+web+store%22+change&hl=en' }},
  { json: { source: 'hn_front', topic: 'hn front-page', url: 'https://hn.algolia.com/api/v1/search_by_date?tags=front_page&query=adblock+OR+%22ad+blocker%22+OR+%22manifest+v3%22+OR+%22youtube+ads%22' }}
];

const items = $input.all();
const out = [];
for (const it of items) {
  const ctx = it.json;
  const body = ctx.data || ctx.body || '';
  const text = typeof body === 'string' ? body : JSON.stringify(body);
  const source = ctx.source || 'unknown';
  const topic = ctx.topic || '';
  if (source === 'hn_front') {
    try {
      const j = JSON.parse(text);
      for (const h of (j.hits || [])) {
        out.push({ json: {
          source: 'hn', url: h.url || ('https://news.ycombinator.com/item?id='+h.objectID),
          title: h.title || h.story_title || '',
          summary: (h.story_text || '').replace(/<[^>]*>/g,'').slice(0,500),
          relevance: topic,
          urgency: (h.points||0) > 100 ? 'high' : 'normal',
          published_at: h.created_at
        }});
      }
    } catch(e) {}
  } else {
    // Parse RSS minimal
    const items_rx = /<item>([\s\S]*?)<\/item>/g;
    let m;
    while ((m = items_rx.exec(text)) !== null) {
      const block = m[1];
      const title = (block.match(/<title>(?:<!\[CDATA\[)?([^<\]]+)/) || [])[1] || '';
      const link = (block.match(/<link>([^<]+)/) || [])[1] || '';
      const desc = (block.match(/<description>(?:<!\[CDATA\[)?([\s\S]*?)\]?\]?<\/description>/) || [])[1] || '';
      const pub = (block.match(/<pubDate>([^<]+)/) || [])[1] || '';
      if (!link) continue;
      out.push({ json: {
        source: 'google_news', url: link, title,
        summary: desc.replace(/<[^>]*>/g,'').slice(0,500),
        relevance: topic, urgency: 'normal',
        published_at: pub
      }});
    }
  }
}
return out;

