const orig = $('Parse news').item.json;
const llm = $input.first().json;
const draft = (llm.response || llm.message?.content || '').trim();
if (!draft || draft.toUpperCase().startsWith('SKIP')) return [];
return [{ json: { ...orig, response_draft: draft }}];
